// Validation test for the $host() styles fix
import { compile } from './packages/svelte/src/compiler/index.js';

const test_component = `
<svelte:options customElement={{tag: "test-counter"}}/>

<script>
  import {onMount} from "svelte";

  let Host = $host();

  $effect(() => {
    console.log("EFFECT: shadowRoot has style element:", Boolean(Host.shadowRoot?.querySelector('style')));
    console.log("EFFECT: shadowRoot innerHTML has style tag:", Host.shadowRoot?.innerHTML?.includes('<style>') || false);
  });

  onMount(() => {
    console.log("ONMOUNT: shadowRoot has style element:", Boolean(Host.shadowRoot?.querySelector('style')));
    console.log("ONMOUNT: shadowRoot innerHTML has style tag:", Host.shadowRoot?.innerHTML?.includes('<style>') || false);

    setTimeout(() => {
      console.log("DELAYED: shadowRoot has style element:", Boolean(Host.shadowRoot?.querySelector('style')));
      console.log("DELAYED: shadowRoot innerHTML has style tag:", Host.shadowRoot?.innerHTML?.includes('<style>') || false);
    }, 10);
  });
</script>

<button class="btn">Test Button</button>

<style>
  .btn {
    width: 100px;
    height: 50px;
    background: blue;
  }
</style>
`;

console.log("=== Validating the style availability fix ===\n");

// Compile the component
const compiled = compile(test_component, {
  generate: 'client',
  customElement: true
});

console.log("Compiled successfully ✅");

// Check if the compiled code contains our synchronous style handling
const compiledCode = compiled.js.code;

// Look for append_styles calls to verify the fix
if (compiledCode.includes('$.append_styles')) {
  console.log("Found append_styles usage ✅");

  // Check if the CSS is being included
  if (compiled.css?.code) {
    console.log("CSS styles detected ✅");
  } else {
    console.log("❌ No CSS styles found");
  }

  // Analyze the compiled code structure
  const effectPosition = compiledCode.indexOf('$.user_effect');
  const appendStylesPosition = compiledCode.indexOf('$.append_styles');
  const onMountPosition = compiledCode.indexOf('onMount');

  if (effectPosition > -1 && appendStylesPosition > -1 && onMountPosition > -1) {
    // Check the order - append_styles should be called before effects in the code
    if (appendStylesPosition < effectPosition && appendStylesPosition < onMountPosition) {
      console.log("append_styles called before effects and onMount ✅");
    } else {
      console.log("⚠️  append_styles position needs verification");
    }
  }
} else {
  console.log("❌ append_styles not found in compiled code");
}

console.log("\n=== Test Summary ===");
console.log("The fix adds synchronous style appending for custom elements.");
console.log("Styles should now be available in both onMount() and $effect() synchronously.");
console.log("\n=== Next Steps ===");
console.log("1. Run browser tests to verify the fix works end-to-end");
console.log("2. Check that regular components still work correctly");
console.log("3. Ensure no regressions in production builds");

